import React, { useState, useEffect, useRef } from 'react';
import { useSearchParams } from 'react-router-dom';
import Navbar from '../components/Navbar';

const API = '';

export default function Project() {
  const [searchParams, setSearchParams] = useSearchParams();
  const [projects, setProjects] = useState([]);
  const [kategoriList, setKategoriList] = useState([]);
  const filterKategori = parseInt(searchParams.get('kategori')) || 0;
  const [isLoaded, setIsLoaded] = useState(false);
  const cardRefs = useRef([]);

  // RESET SCROLL KE ATAS SAAT KOMPONEN DI-MOUNT
  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  useEffect(() => {
    const url = filterKategori > 0
      ? `${API}/api/projects/public?kategori=${filterKategori}`
      : `${API}/api/projects/public`;
    fetch(url).then(r => r.json()).then(setProjects).catch(console.error);
  }, [filterKategori]);

  useEffect(() => {
    fetch(`${API}/api/kategori`).then(r => r.json()).then(setKategoriList).catch(console.error);
  }, []);

  useEffect(() => {
    const timer = setTimeout(() => {
      setIsLoaded(true);
    }, 100);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    if (!isLoaded) return;

    cardRefs.current.forEach((el) => {
      if (el) {
        el.style.opacity = '0';
        el.style.transform = 'translateY(30px)';
        el.style.transition = 'all 0.7s cubic-bezier(0.34,1.56,0.64,1)';
      }
    });
    const timer = setTimeout(() => {
      cardRefs.current.forEach((el, i) => {
        if (el) {
          setTimeout(() => {
            el.style.opacity = '1';
            el.style.transform = 'translateY(0)';
          }, i * 80);
        }
      });
    }, 50);
    return () => clearTimeout(timer);
  }, [isLoaded, projects]);

  return (
    <>
      <style>{`
        :root {
          --choco-900: #24140f;
          --choco-800: #321c14;
          --choco-700: #4a2a1d;
          --cream-50: #fff8ed;
          --cream-100: #f6ead7;
          --cream-200: #ead5b8;
          --caramel: #c98545;
          --gradient-main: linear-gradient(135deg, #4a2a1d 0%, #8a4b2a 54%, #c98545 100%);
          --gradient-glass: linear-gradient(145deg, rgba(50, 28, 20, 0.94), rgba(36, 20, 15, 0.88));
          --glass-bg: rgba(50, 28, 20, 0.90);
          --glass-border: rgba(255, 248, 237, 0.16);
          --glass-shadow: 0 24px 80px rgba(36, 20, 15, 0.18), inset 0 1px 0 rgba(255, 248, 237, 0.12);
          --radius-lg: 28px;
          --radius-md: 18px;
          --transition: all 0.5s cubic-bezier(0.34, 1.56, 0.64, 1);
        }

        * { margin: 0; padding: 0; box-sizing: border-box; }

        body {
          background:
            radial-gradient(circle at 18% 10%, rgba(201, 133, 69, 0.16), transparent 30%),
            radial-gradient(circle at 84% 92%, rgba(74, 42, 29, 0.12), transparent 28%),
            linear-gradient(180deg, var(--cream-50) 0%, var(--cream-100) 100%);
          min-height: 100vh;
          position: relative;
          overflow-x: hidden;
        }

        body::before {
          content: '';
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          background:
            radial-gradient(ellipse at 18% 18%, rgba(36, 20, 15, 0.28) 0 7px, rgba(201, 133, 69, 0.26) 8px 15px, transparent 16px),
            radial-gradient(ellipse at 72% 28%, rgba(74, 42, 29, 0.24) 0 6px, rgba(201, 133, 69, 0.22) 7px 13px, transparent 14px),
            radial-gradient(ellipse at 36% 74%, rgba(36, 20, 15, 0.22) 0 5px, rgba(201, 133, 69, 0.20) 6px 12px, transparent 13px);
          background-size: 145px 130px, 175px 155px, 190px 170px;
          opacity: 0.72;
          mask-image:
            radial-gradient(circle at 0 0, #000 0 20%, transparent 36%),
            radial-gradient(circle at 100% 0, #000 0 20%, transparent 36%),
            radial-gradient(circle at 0 100%, #000 0 20%, transparent 36%),
            radial-gradient(circle at 100% 100%, #000 0 20%, transparent 36%);
          -webkit-mask-image:
            radial-gradient(circle at 0 0, #000 0 20%, transparent 36%),
            radial-gradient(circle at 100% 0, #000 0 20%, transparent 36%),
            radial-gradient(circle at 0 100%, #000 0 20%, transparent 36%),
            radial-gradient(circle at 100% 100%, #000 0 20%, transparent 36%);
        }

        @keyframes floatOrb {
          0%,100%{transform:translate(0,0)scale(1)}
          25%{transform:translate(40px,-50px)scale(1.15)}
          50%{transform:translate(-25px,25px)scale(0.85)}
          75%{transform:translate(50px,35px)scale(1.1)}
        }
        @keyframes gradientMove {
          0%,100%{background-position:0% 50%}
          50%{background-position:100% 50%}
        }
        @keyframes shimmer {
          0%,100%{background-position:0% 50%}
          50%{background-position:100% 50%}
        }
        @keyframes fadeInUp {
          from {
            opacity: 0;
            transform: translateY(50px) scale(0.96);
          }
          to {
            opacity: 1;
            transform: translateY(0) scale(1);
          }
        }
        @keyframes heartBeat {
          0%,100%{transform:scale(1)}
          14%{transform:scale(1.3)}
          28%{transform:scale(1)}
          42%{transform:scale(1.3)}
          56%{transform:scale(1)}
        }

        .bg-orb{position:absolute;border-radius:50%;filter:blur(100px);animation:floatOrb 25s ease-in-out infinite}
        .bg-orb:nth-child(1){width:500px;height:500px;background:#c98545;top:-200px;right:-150px;opacity:0.15}
        .bg-orb:nth-child(2){width:400px;height:400px;background:#8a4b2a;bottom:-150px;left:-120px;animation-delay:-8s;opacity:0.20}
        .bg-orb:nth-child(3){width:350px;height:350px;background:#4a2a1d;top:40%;left:30%;animation-delay:-16s;opacity:0.15}

        .main-content{position:relative;z-index:1;padding-top:100px}

        .page-header-glass{
          background:var(--gradient-glass);
          border:1px solid var(--glass-border);
          box-shadow:var(--glass-shadow);
          border-radius:var(--radius-lg);
          padding:2.5rem 3rem;
          margin-bottom:2rem;
          position:relative;
          overflow:hidden;
          color:#fff8ed;
          animation: fadeInUp 0.8s cubic-bezier(0.34, 1.56, 0.64, 1);
        }
        .page-title{
          font-size:2.5rem;
          font-weight:900;
          margin-bottom:0.5rem;
          letter-spacing:-0.5px;
          color:#fff8ed;
        }
        .page-title .gradient-text{
          background:linear-gradient(120deg,#fff8ed 0%,#f1c28a 35%,#fff2d8 55%,#c98545 78%,#fff8ed 100%);
          -webkit-background-clip:text;
          -webkit-text-fill-color:transparent;
          background-clip:text;
          background-size:260% 260%;
          animation:gradientMove 4s ease-in-out infinite;
        }
        .page-title i{color:#f1c28a}
        .page-subtitle{color:rgba(255,248,237,0.72);font-size:1rem}

        /* FILTER BUTTON - Default Cream, Active Choco */
        .filter-section{
          margin-bottom:2rem;
          display:flex;
          flex-wrap:wrap;
          justify-content:center;
          gap:0.5rem;
          animation: fadeInUp 0.9s cubic-bezier(0.34, 1.56, 0.64, 1);
        }
        .filter-btn{
          padding:0.5rem 1.4rem;
          border-radius:50px;
          border:1px solid rgba(74,42,29,0.12);
          background:linear-gradient(135deg, #f6ead7, #fff8ed);
          color:#4a2a1d;
          text-decoration:none;
          font-size:0.88rem;
          font-weight:600;
          transition:var(--transition);
          cursor:pointer;
          flex-shrink:0;
        }
        .filter-btn:hover{
          background:linear-gradient(135deg, #ead5b8, #f6ead7);
          transform:translateY(-2px);
          box-shadow:0 4px 16px rgba(36,20,15,0.10);
        }
        .filter-btn.active{
          background:linear-gradient(135deg, #4a2a1d, #8a4b2a);
          color:#fff8ed;
          border-color:transparent;
          font-weight:700;
          box-shadow:0 4px 16px rgba(36,20,15,0.20);
        }
        .filter-btn.active:hover{
          background:linear-gradient(135deg, #321c14, #6b3a1f);
        }

        .project-card{
          background:var(--gradient-glass);
          border-radius:var(--radius-lg);
          overflow:hidden;
          border:1px solid var(--glass-border);
          box-shadow:var(--glass-shadow);
          transition:var(--transition);
          height:100%;
          color:var(--cream-50);
        }
        .project-card:hover{transform:translateY(-8px);box-shadow:0 24px 80px rgba(36,20,15,0.20)}
        .project-card-img{
          width:100%;
          height:200px;
          object-fit:cover;
          display:block;
        }
        .project-card-body{padding:1.5rem}
        .project-card-title{
          font-size:1.05rem;
          font-weight:700;
          color:#fff8ed;
          margin-bottom:0.3rem;
          display:block;
        }
        .project-card-kategori{
          font-size:0.8rem;
          color:#f1c28a;
          font-weight:600;
          display:block;
          margin-bottom:0.5rem;
        }
        .project-card-desc{
          font-size:0.88rem;
          color:rgba(255,248,237,0.72);
          margin-bottom:1rem;
          display:-webkit-box;
          -webkit-line-clamp:3;
          -webkit-box-orient:vertical;
          overflow:hidden;
        }
        .project-tech{
          display:flex;
          flex-wrap:wrap;
          gap:0.35rem;
          margin-bottom:1rem;
        }
        .project-tech-badge{
          background:rgba(255,248,237,0.10);
          color:#f1c28a;
          padding:0.25rem 0.75rem;
          border-radius:50px;
          font-size:0.75rem;
          font-weight:600;
          border:1px solid rgba(255,248,237,0.14);
          flex-shrink:0;
        }
        .project-tech-badge:hover{
          background:linear-gradient(135deg,#fff2d8,#c98545);
          color:#24140f;
          border-color:transparent;
        }
        .project-card-links{display:flex;gap:0.75rem;flex-wrap:wrap}
        .project-card-links a{
          display:inline-flex;
          align-items:center;
          gap:0.4rem;
          font-size:0.82rem;
          font-weight:600;
          color:#f1c28a;
          text-decoration:none;
          padding:0.4rem 1rem;
          border-radius:50px;
          border:1px solid rgba(255,248,237,0.14);
          background:rgba(255,248,237,0.08);
          transition:var(--transition);
          flex-shrink:0;
        }
        .project-card-links a:hover{
          background:linear-gradient(135deg,#fff2d8,#c98545);
          color:#24140f;
          border-color:transparent;
          transform:translateY(-2px);
        }

        .glass-card{
          background:var(--gradient-glass);
          border-radius:var(--radius-lg);
          border:1px solid var(--glass-border);
          box-shadow:var(--glass-shadow);
          padding:2rem;
          color:var(--cream-50);
        }
        .footer-glass{
          background:var(--gradient-glass);
          border-top:1px solid var(--glass-border);
          padding:1.5rem 0;
          margin-top:4rem;
        }
        .footer-text{
          font-size:0.9rem;
          color:rgba(255,248,237,0.72);
        }
        .heart{
          color:#d79a58;
          display:inline-block;
          animation:heartBeat 1.5s ease-in-out infinite;
        }
        .code-icon{
          background:linear-gradient(135deg,#fff2d8,#d79a58,#8a4b2a);
          -webkit-background-clip:text;
          -webkit-text-fill-color:transparent;
          background-clip:text;
        }

        .text-muted{color:rgba(255,248,237,0.66)!important}

        /* RESPONSIVE MOBILE */
        @media(max-width:768px){
          .main-content{padding-top:80px}
          .page-header-glass{padding:2rem 1.5rem}
          .page-title{font-size:1.8rem}
          .project-card-img{height:180px}
          .filter-btn{
            padding:0.4rem 1rem;
            font-size:0.75rem;
          }
        }
        @media(max-width:576px){
          .main-content{padding-top:75px}
          .page-header-glass{padding:1.5rem 1rem}
          .page-title{font-size:1.5rem}
          .page-subtitle{font-size:0.85rem}
          .project-card-img{height:150px}
          .project-card-body{padding:1rem}
          .project-card-title{font-size:0.95rem}
          .project-card-desc{font-size:0.8rem;margin-bottom:0.6rem}
          .project-tech-badge{font-size:0.65rem;padding:0.15rem 0.6rem}
          .project-card-links a{padding:0.3rem 0.8rem;font-size:0.7rem}
          .project-card-kategori{font-size:0.7rem}
          .filter-btn{
            padding:0.3rem 0.8rem;
            font-size:0.7rem;
          }
          .filter-section{gap:0.3rem}
          .footer-text{font-size:0.75rem}
        }
      `}</style>
      <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css" />
      <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.7.2/css/all.min.css" />

      <div style={{ position: 'fixed', inset: 0, zIndex: 0, overflow: 'hidden', pointerEvents: 'none' }}>
        <div className="bg-orb"></div>
        <div className="bg-orb"></div>
        <div className="bg-orb"></div>
      </div>

      <Navbar />

      <div className="main-content">
        <div className="container">
          <div className="page-header-glass">
            <h1 className="page-title">
              <i className="fas fa-folder-open me-2"></i>
              <span className="gradient-text">Project Portfolio</span>
            </h1>
            <p className="page-subtitle">Kumpulan project yang telah saya kerjakan</p>
          </div>

          <div className="filter-section">
            <button
              className={`filter-btn ${filterKategori === 0 ? 'active' : ''}`}
              onClick={() => setSearchParams({})}
            >
              <i className="fas fa-th me-1"></i>Semua
            </button>
            {kategoriList.map((k) => (
              <button
                key={k.id}
                className={`filter-btn ${filterKategori === k.id ? 'active' : ''}`}
                onClick={() => setSearchParams({ kategori: k.id })}
              >
                {k.kategori}
              </button>
            ))}
          </div>

          {projects.length > 0 ? (
            <div className="row g-4">
              {projects.map((project, i) => {
                const teknologiList = project.teknologi ? project.teknologi.split('|') : [];
                return (
                  <div className="col-md-6 col-lg-4 col-12" key={project.id}>
                    <div className="project-card" ref={(el) => { cardRefs.current[i] = el; }}>
                      {project.gambar ? (
                        <img src={`/uploads/${project.gambar}`} alt={project.nama_project} className="project-card-img" />
                      ) : (
                        <div className="project-card-img d-flex align-items-center justify-content-center"
                          style={{ background: 'linear-gradient(135deg,#f5e5cd 0%,#fff8ed 100%)' }}>
                          <i className="fas fa-image" style={{ fontSize: '3rem', color: '#8a4b2a' }}></i>
                        </div>
                      )}
                      <div className="project-card-body">
                        <span className="project-card-title">{project.nama_project}</span>
                        <span className="project-card-kategori">{project.kategori}</span>
                        <p className="project-card-desc">{project.deskripsi}</p>
                        <div className="project-tech">
                          {teknologiList.map((t, j) => (
                            <span className="project-tech-badge" key={j}>{t}</span>
                          ))}
                        </div>
                        <div className="project-card-links">
                          {project.github && (
                            <a href={project.github} target="_blank" rel="noreferrer">
                              <i className="fab fa-github me-1"></i><span>GitHub</span>
                            </a>
                          )}
                          {project.demo && (
                            <a href={project.demo} target="_blank" rel="noreferrer">
                              <i className="fas fa-external-link-alt me-1"></i><span>Demo</span>
                            </a>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          ) : (
            <div className="glass-card text-center py-5">
              <i className="fas fa-inbox" style={{ fontSize: '4rem', color: '#8a4b2a' }}></i>
              <h5 className="mt-3 text-muted">Belum ada project</h5>
            </div>
          )}
        </div>
      </div>

      <footer className="footer-glass">
        <div className="container">
          <div className="text-center footer-text">
            <span className="code-icon"><i className="fas fa-code me-1"></i></span> Dibuat dengan{' '}
            <span className="heart"><i className="fas fa-heart"></i></span>{' '}
            oleh Hagia Sofiana &bull; {new Date().getFullYear()}
          </div>
        </div>
      </footer>
    </>
  );
}
